import React, { useEffect, useState } from 'react';
import { getSplits, addSplit, deleteSplit, toggleMemberPaid } from '../utils/api';

const fmt = (n) => '₹' + Number(n).toLocaleString('en-IN');

export default function Split() {
  const [splits, setSplits] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [form, setForm] = useState({ title: '', totalAmount: '', members: [{ name: '', share: '' }] });

  useEffect(() => { load(); }, []);
  const load = async () => { const res = await getSplits(); setSplits(res.data); };

  const addMember = () => setForm({ ...form, members: [...form.members, { name: '', share: '' }] });
  const removeMember = (i) => setForm({ ...form, members: form.members.filter((_, idx) => idx !== i) });
  const updateMember = (i, field, val) => {
    const m = [...form.members];
    m[i][field] = val;
    setForm({ ...form, members: m });
  };

  const handleAdd = async (e) => {
    e.preventDefault();
    await addSplit(form);
    setShowModal(false);
    setForm({ title: '', totalAmount: '', members: [{ name: '', share: '' }] });
    load();
  };

  const handleDelete = async (id) => {
    if (window.confirm('Delete this split?')) { await deleteSplit(id); load(); }
  };

  const handleToggle = async (splitId, memberId) => {
    await toggleMemberPaid(splitId, memberId);
    load();
  };

  return (
    <div>
      <div className="page-header">
        <div>
          <div className="page-title">🔀 Split</div>
          <div className="page-subtitle">Split bills and track who owes what</div>
        </div>
        <button className="btn btn-primary" onClick={() => setShowModal(true)}>+ New Split</button>
      </div>

      {splits.length === 0 ? (
        <div className="card">
          <div className="empty-state">
            <div className="empty-icon">🔀</div>
            <h3>No splits yet</h3>
            <p>Create a split to track shared expenses</p>
          </div>
        </div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
          {splits.map(s => {
            const paid = s.members.filter(m => m.paid).reduce((sum, m) => sum + m.share, 0);
            const total = s.totalAmount;
            const pct = Math.min(100, (paid / total) * 100);
            return (
              <div className="card" key={s._id}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 14 }}>
                  <div>
                    <div style={{ fontSize: 17, fontWeight: 700 }}>{s.title}</div>
                    <div style={{ fontSize: 12, color: 'var(--text3)', marginTop: 3 }}>
                      Total: {fmt(total)} · {new Date(s.date).toLocaleDateString('en-IN')}
                    </div>
                  </div>
                  <button className="icon-btn icon-btn-danger" onClick={() => handleDelete(s._id)}>🗑️</button>
                </div>

                <div className="progress-bar">
                  <div className="progress-fill" style={{ width: `${pct}%`, background: 'var(--green)' }} />
                </div>
                <div style={{ fontSize: 12, color: 'var(--text3)', margin: '6px 0 14px', textAlign: 'right' }}>
                  {fmt(paid)} collected of {fmt(total)}
                </div>

                <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                  {s.members.map(m => (
                    <div key={m._id} style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '10px 14px', background: 'var(--bg3)', borderRadius: 10 }}>
                      <div style={{ width: 32, height: 32, borderRadius: '50%', background: m.paid ? 'rgba(0,229,160,0.2)' : 'rgba(255,77,109,0.1)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 13, fontWeight: 700, color: m.paid ? 'var(--green)' : 'var(--red)' }}>
                        {m.name[0]?.toUpperCase()}
                      </div>
                      <div style={{ flex: 1 }}>
                        <div style={{ fontSize: 13, fontWeight: 600 }}>{m.name}</div>
                        <div style={{ fontSize: 12, color: 'var(--text3)' }}>{fmt(m.share)}</div>
                      </div>
                      <button
                        className={`btn btn-sm ${m.paid ? 'btn-ghost' : 'btn-primary'}`}
                        onClick={() => handleToggle(s._id, m._id)}
                      >
                        {m.paid ? '✓ Paid' : 'Mark Paid'}
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      )}

      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <h2>New Split</h2>
            <form onSubmit={handleAdd}>
              <div className="form-row">
                <div className="form-group">
                  <label>Title</label>
                  <input value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} placeholder="e.g. Goa Trip" required />
                </div>
                <div className="form-group">
                  <label>Total Amount (₹)</label>
                  <input type="number" value={form.totalAmount} onChange={e => setForm({ ...form, totalAmount: e.target.value })} placeholder="0" required />
                </div>
              </div>

              <div style={{ marginBottom: 8, fontSize: 12, fontWeight: 600, color: 'var(--text2)', textTransform: 'uppercase', letterSpacing: '0.5px' }}>Members</div>
              {form.members.map((m, i) => (
                <div key={i} style={{ display: 'flex', gap: 8, marginBottom: 8 }}>
                  <input placeholder="Name" value={m.name} onChange={e => updateMember(i, 'name', e.target.value)} style={{ flex: 2, padding: '10px 12px', background: 'var(--bg3)', border: '1px solid var(--border)', borderRadius: 10, color: 'var(--text)', fontFamily: 'Sora, sans-serif', outline: 'none' }} required />
                  <input type="number" placeholder="₹ Share" value={m.share} onChange={e => updateMember(i, 'share', e.target.value)} style={{ flex: 1, padding: '10px 12px', background: 'var(--bg3)', border: '1px solid var(--border)', borderRadius: 10, color: 'var(--text)', fontFamily: 'Sora, sans-serif', outline: 'none' }} required />
                  {form.members.length > 1 && (
                    <button type="button" className="icon-btn icon-btn-danger" onClick={() => removeMember(i)}>✕</button>
                  )}
                </div>
              ))}
              <button type="button" className="btn btn-ghost btn-sm" onClick={addMember} style={{ marginBottom: 16 }}>+ Add Member</button>

              <div className="form-actions">
                <button type="button" className="btn btn-ghost" onClick={() => setShowModal(false)}>Cancel</button>
                <button type="submit" className="btn btn-primary">Create Split</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
